var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네?","JPN":"モネ？","ENG":"Mone?","TWN":"莫妮？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네?","JPN":"モネネ？","ENG":"Monene?","TWN":"莫妮妮？"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네네!","JPN":"モネネ！","ENG":"Monene!","TWN":"莫妮妮！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L5_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네! 모네!","JPN":"モネ！　モネ！","ENG":"Mone! Mone!","TWN":"莫妮！莫妮！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L6_1","type":"dialog","speaker":"TONFA_PENGUIN_NULL_NULL","text":{"KOREA":"모네에!","JPN":"モネエ！","ENG":"Moneee!","TWN":"莫妮！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_PENGUIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"실물로 보는 건 처음인데……. 정말 예쁜 마을이야.","JPN":"実物を見るのは初めてだけど……本当にきれいな村ね。","ENG":"This is the first time I actually saw the village...","TWN":"第一次親眼看到……真是個漂亮的村莊。"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"큭, 이 거리를 선배님과 단둘이 걸을 수 있었다면…….","JPN":"この景色を先輩と二人きりで観ながら散歩できたなら……","ENG":"If I could walk this street with Dark...","TWN":"嗚，真希望能和前輩單獨走在這條街上……"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"오늘에야말로 내 진심을 고백할 수 있었을지도 모르는데……!","JPN":"今日こそ私の気持ちを告白できたかもしれないのに……!","ENG":"Maybe I’d be able to confess my love for him...","TWN":"今天或許很適合告白……!"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그래! 지금 가자! 선배님을 찾아가서 말씀드리는 거야!","JPN":"そうだ！　今行こう！　先輩のところに行って話をしよう！","ENG":"Yes, let’s go! I’ll tell Dark!","TWN":"沒錯！現在就去吧！去跟前輩告白！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"선배님과 함께 최강의 악당이 되고 싶다고!","JPN":"先輩と一緒に最強の悪党になりたいって！","ENG":"That I want to be the ultimate villain along with him!","TWN":"我要和前輩一起成爲地表最強反派！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"하하하하하하! 아하하하하하!","JPN":"ハハハハハハハ！　アハハハハ！","ENG":"Hah hah hah hah! Ah hah hah hah!","TWN":"哈哈哈哈哈！哇哈哈哈哈哈！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"……하, 하?","JPN":"……ハ……ハ……？","ENG":"... Hah... Hah?","TWN":"…哈，哈！"},"stage":{"bg":"VILLAGE2","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"그렇지만 곤란하네요. 마실 것도 먹을 것도 잔뜩 준비해 뒀는데 이래선 손님이 없어요.","JPN":"困りましたね。飲み物も食べ物もいっぱい用意したのに、お客さんがいないなんて。","ENG":"What do I do? I brought so much food and drinks, but we don’t have any customers here.","TWN":"真是尷尬，準備這麼多飲料和食物，結果卻沒客人上門。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앗, 손님 필요하세요? 제가 가서 모셔들 올까요?","JPN":"あっ、お客様が必要ですか？　私が連れてきましょうか？","ENG":"Do you need customers? Shall I go get them?","TWN":"喔？你需要客人嗎？要我去帶客人來？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그건 납치지 말임다?!","JPN":"それは攫ってくるってことっすか！？","ENG":"Isn’t that kidnapping, ma’am?","TWN":"那應該是綁架吧？！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LARA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"흥. 그 난리가 났는데 누가 여기 오려고 하겠어.","JPN":"ふん。あんな大騒ぎになったのに、誰がここに来ようとするのよ。","ENG":"Hmpf, no one will come here after all this.","TWN":"哼，發生這種事誰還敢來這裡？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"결국 <color=#ffd34c>그리고 모두 다 행복하게 살았습니다</color> 엔딩은 동화책에나 나오는 거지, 뭐.","JPN":"結局<color=#ffd34c>そしてずっと幸せに暮らしましたとさ。めでたし、めでたし。</color>の結末なんか童話だけの話なの。","ENG":"So, <color=#ffd34c>”everyone lived happily ever after”</color> is something from a fairy tale.","TWN":"<color=#ffd34c>大家一起度著幸福快樂的日子</color>，這種結局只會在童話裡出現吧！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"아얏!","JPN":"痛っ！","ENG":"Ow!","TWN":"哎呀！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"시그마 아가씨 앞입니다, 리코리스. 순진한 아가씨의 동심을 부수려고 하지 마세요.","JPN":"シグマお嬢様の前です、リコリス。純粋なお嬢様の童心を傷つけないでください。","ENG":"Lycoris, Sigma is here. Don’t ruin her innocence.","TWN":"莉克麗絲，在西格瑪小姐面前請注意發言，不要毀掉小姐的童年。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"아냐. 난 괜찮아. 진짜 해적도 만날 수 있었는걸.","JPN":"ううん、私は大丈夫だよ。本物の海賊にも会えたからね。","ENG":"No, I’m okay. I even met a real pirate.","TWN":"沒關係，起碼我有見到真正的海盜呢。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"그러니까 바다로 가자, 아빠!","JPN":"だから海に行こう、パパ！","ENG":"So daddy, let’s go to the sea!","TWN":"爸爸，我們去海裡吧！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"이 해변엔 해적 언니가 있으니까 보물도 숨겨져 있을 거야!","JPN":"この海には海賊のお姉ちゃんがいるから、きっと宝物も隠されているはず！","ENG":"Since a pirate is here, there must be treasure hidden somewhere nearby!","TWN":"海盜姊姊在這邊，那寶藏應該也藏在這裡吧！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"선장님! 충성스러운 선원 모네를 잊지 말아 주십셔!","JPN":"船長！　忠誠心深い船員のモネを忘れないでほしいっす！","ENG":"Captain! Please remember your local crew Mone, ma’am!","TWN":"船長！請不要忘記您最忠心的船員 莫妮唷！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L37_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"물론이지, 모네 선원!","JPN":"もちろんだ、モネ船員！","ENG":"Of course, Mone!","TWN":"那當然，莫妮船員！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"무서운 상어 떼를 넘어서려면 모래 아빠상을 만들어야 한다, 얼!","JPN":"怖いサメの群れを越えていくためには、砂のパパ像を作らねばならないぞ！","ENG":"We have to make a sand statue of my daddy to overcome the sharks, err!","TWN":"要越過可怕的鯊魚群，就必須堆爸爸沙雕像！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"예쓰얼! 무지 크게 만들겠슴다!","JPN":"はいっす！　とびっきりデカいのを作るっす！","ENG":"Yes, ma’am! I’ll make a huge one, arrr!","TWN":"好的唷！我會堆一個超巨大的！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그러고 보니 오늘이 벌써 전사 휴무 마지막 날이로군.","JPN":"そういえば今日で全社休業も最終日だな。","ENG":"So this is the last day of our company vacation.","TWN":"不過今天已經是全公司放假的最後一天了呢！"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L43_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"네. 내일부터는 또 업무가 잔뜩 몰려들겠죠.","JPN":"はい。明日からはまた業務に追われる日々が続くでしょう。","ENG":"Yes, so much work will be waiting for us tomorrow.","TWN":"是啊，明天開始又會有一大堆工作在等著我吧。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그래도 제 흑역사가 얌전히 돌아가서 다행입니다. 마음은 놓이네요.","JPN":"でも私の黒歴史が大人しく戻ってくれてよかったです。安心しました。","ENG":"But still, I’m glad the worst version of past-me left without causing any trouble.","TWN":"幸好我的黑歷史已經乖乖回去了，可以安心了。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"모더레이터를 쓰러뜨린 뒤 사라졌지, 아마?","JPN":"モデレーターを倒した後消えたな、おそらく。","ENG":"She just disappeared after the Moderator was gone, right?","TWN":"打倒仲裁者後好像就沒看到她了，應該是回去了吧？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"어쩌면 과거의 자네가 남은 시간만이라도 푹 쉴 수 있게 도우러 온 걸지도 모르겠군.","JPN":"もしかしたら過去の君は、残りの時間だけでもゆっくり休めるように助けに来てくれたのかもしれないな。","ENG":"Maybe she came here to help you relax for the rest of the vacation.","TWN":"也許是過去的你為了讓現在的你，能夠在剩餘的假期中好好休息，才來幫你的吧？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"필요없습니다. 그런 도움.","JPN":"そんな助けは必要ありません。","ENG":"That’s something that I don’t need.","TWN":"不必了。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_LAUGH"}}}},{"id":"L50_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"먼 길 오셨는데, 그냥 가시게요?","JPN":"せっかくこんな遠い所までいらしたのに、もう帰られるのですか？","ENG":"You came this far, and now you’re leaving?","TWN":"好不容才來一趟，這麼快就要走啦？"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"네. 마을이 평화를 되찾았으니 제가 지닌 재주는 주인님께 불필요합니다.","JPN":"はい。村が平和を取り戻しましたので、私の力はご主人様には不要です。","ENG":"Yes, the village is at peace now. The Master doesn’t need me here.","TWN":"是的。既然村莊已經恢復平靜，那主人應該暫時不會需要我。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"지금은 편안히 휴식을 취하실 수 있도록 물러나 있어야겠죠.","JPN":"今はゆっくりできるように、静かに元の場所に戻るべきでしょう。","ENG":"I’ll be going so that my Master can get some rest.","TWN":"現在是時候退下，讓主人可以好好休息。"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"그렇지만 모네도 메이드장님과 함께 휴가를 보내는 편이 더…….","JPN":"でも、モネもメイド長さんと一緒に休みを過ごせたほうが喜びそうで……","ENG":"But Mone would love to spend some time with you...","TWN":"但女僕長也一起的話，莫妮會更…"},"stage":{"bg":"VILLAGE1","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"어? 저건…… 함선들이네요? 어째서 저렇게나 많이……?","JPN":"あら？　あれは……艦船ですね。どうしてあんなにたくさん……","ENG":"Hm? I see... ships. So many of them...","TWN":"呃？那是… 艦船？怎麼那麼多……？"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"미하~ 시청자 여러분, 저기 보이세요~?","JPN":"ミハ～！　視聴者の皆さん、見えますか？","ENG":"Hi, everyone! Do you see this?","TWN":"米婭 hi～觀衆朋友們，你們有看到嗎～？"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"지금 저희 발 아래 엄청 예쁜 바다가 펼쳐져 있어요!","JPN":"今、私たちの下にはとても綺麗な海が広がっています！","ENG":"The sea here is so beautiful!","TWN":"現在在我們腳底下的，是一片美麗的海洋！"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"RUMI_HB_NULL_NULL","text":{"KOREA":"침식체가 없잖아? 이럴 줄 알았으면 수영복 챙겨 오는 건데!","JPN":"侵食体がいないじゃん！　こんなんだったら水着を持ってくればよかった！","ENG":"I don’t see any C.O.s here. I should have brought a swimsuit!","TWN":"根本就沒有侵蝕體嘛！早知道我就帶泳衣來啦！"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RUMI_HB_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"여기는 데이마인 채굴 4팀. 토벌전 연락을 받고 왔는데……. 뭔가 이상하군.","JPN":"こちらはデイマイン採掘4チーム。討伐戦の連絡を受けて来たが……何か変だな。","ENG":"This is Daymine Mining Team 4. We heard the raid was here, but... something is not right.","TWN":"這裡是戴瑪因第四採礦隊。我收到討伐戰的通知……但怎麼好像怪怪的？"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"팀장님, 저희 여기서 조금만 쉬었다 가면 안 돼요? 수영장은 다 꽉 찼던데!","JPN":"班長、ここで少しだけ一息つくのはダメですか？　プールも人でいっぱいでしたよ！","ENG":"Boss, can we stay here for a while? The pool is already full!","TWN":"隊長，我們可以在這邊休息一下再出發嗎？泳池人很多欸！"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"맞습니다, 팀장님. 다른 분들 물놀이 안전을 위해서라도 말이죠.","JPN":"そうですね、班長。他の方の水遊びの安全のためにもなると思います。","ENG":"Yes, boss. For the safety of others in the water as well.","TWN":"是的，隊長，考慮到民眾的戲水安全，這樣比較好。"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠, 주민들의 안위를 위해 도착했습니다.","JPN":"ゾディアックナイツ、住民の安全のために只今参りました。","ENG":"Zodiac Knights are here to protect the villagers.","TWN":"十二宮騎士團，來到這裡守護人民的安全！"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그런데 침식파 반응은……. 감지되지 않는군요.","JPN":"しかし侵食波の反応は……感知できませんね。","ENG":"But... I don’t sense any Corruption Rays.","TWN":"但似乎……沒感應到侵蝕波？"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"우와~! 부단장님, 무척 깨끗하고 파란 바다에요~!","JPN":"うわぁ～！　副団長、とてもきれいで青い海です！","ENG":"Wow, Deputy Commander, the sea is so clear!","TWN":"哇～！副團長你看，海水好藍好清澈喔～！"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"에, 에리어스! 놀러 온 거 아닙니다! 강하하지 마요!","JPN":"ア、アリウス！　遊びに来たわけではありません！　降下しないでください！","ENG":"A-Arius, we’re not here to play! Don’t go down!","TWN":"埃…埃里奧斯！我們不是來這裡玩的！先不要降落！"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐야, 별거 없네. 엄청난 녀석이 나타났다고 다들 호들갑이더니.","JPN":"何だ、大したことないな。すごいやつが現れたとみんな大騒ぎだったのに。","ENG":"I don’t see much here. Everyone was fussing about a super strong enemy.","TWN":"什麼嘛，大家在那邊大驚小怪的，還以為多厲害咧！"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"비상 대기 하던 너한테는 오히려 잘된 일이잖아?","JPN":"非常待機してたミナにはむしろ良かったんじゃない？","ENG":"You’ve been standing by the whole time. So this is a good thing, right?","TWN":"這對在緊急待命的你來說，不是反而是件好事嗎？"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"역시 우리 미나를 따라다니면 행운이 굴러 들어온다니까?","JPN":"やっぱりミナについて行けば、ラッキーなことがあるね！","ENG":"I knew hanging out with you would bring me good luck, Mina.","TWN":"果然跟著米娜好運就會滾滾來呢！"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"노, 놀리지 좀 마! 진짜!","JPN":"か、からかわないで！　もう！","ENG":"S-stop teasing me!","TWN":"少…少開我玩笑！討厭！"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 이러니 어째 휴가 즐기시는 분들 방해하러 온 것 같네요.","JPN":"ハハ、なんだか休暇を楽しんでる方を邪魔しに来た感じになりましたね。","ENG":"Hah hah, I feel like we’re disturbing the people on vacation.","TWN":"哈哈，我們好像反而妨礙到那些來度假的人呢？"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 이 더위에 대기시켜 놓고 임원들끼리 참 좋은 곳으로 놀러 왔군.","JPN":"そうだな。あの暑さの中、社員は待機させておいて役員同士でこんな所まで遊びに来ているなんてな。","ENG":"So, the executives were having a good time while we were waiting on standby in the heat.","TWN":"就是說，讓大家在這麼炎熱的天氣下待命，高層們還真是來到個好地方呢！"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"둘 다, 각오는 됐겠지?","JPN":"2人とも、覚悟はできているか？","ENG":"Are you two ready to take the consequences?","TWN":"你們兩個，做好心裡準備吧！"},"stage":{"bg":"SKY","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"그라운드 원의 태스크포스 분들이지 말임다!","JPN":"グラウンド・ワンのタスクフォースカンパニーの方々じゃないっすか！","ENG":"They are the TASKFORCE companies from Ground One, ma’am!","TWN":"是G1特遣勢力的人！"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"흥…….  하여튼 걱정해 주는 사람만 무안해진다니까.","JPN":"ふん……まったく、心配するだけ無駄か。","ENG":"Oh... I guess I shouldn’t have worried too much.","TWN":"哼… 總之，誰闖的禍誰自己收拾。"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"여기야~! 여기~! 다 함께 보물을 찾으러 가자!","JPN":"ここだよ！　ここ！　みんなで宝物を探しに行こう！","ENG":"Here! Here! Let’s go find a hidden treasure!","TWN":"哈囉～!哈囉～！大家一起去尋寶吧!"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"세상에, 손님들이 잔뜩 오셨네요!","JPN":"あらまあ、お客さんがいっぱい来ましたね！","ENG":"Oh my, so many visitors!","TWN":"哇～好多客人喔！"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SERINA_COFFIN_SUMMER_NULL","text":{"KOREA":"어서 가게 문 열어야겠어요! 사장님도 꼭 들러 주셔야 하는 거, 아시죠?","JPN":"早く店を開けなければ！　社長もぜひ立ち寄ってくださいね！　約束ですよ？","ENG":"I have to open the shop now! You know you have to drop by, right, Boss?","TWN":"得趕緊開門做生意囉！老闆也一定要來捧場喔，知道嗎！"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LARA_NPC_NULL_NULL","text":{"KOREA":"앗! 배달부 한 명 안 필요하세요?! 같이 가요!","JPN":"あっ！　お店に配達員は必要ありませんか？　一緒に行きましょう！","ENG":"Oh! Don’t you need a deliverywoman? I want to come with you!","TWN":"喂！需要外送員嗎？！一起走嘛！"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"XIEN_FREEDOM_SUMMER_NULL","text":{"KOREA":"평화로워진 해변이 또 한 번 소란스러워지겠군! 뒤에 타게나, 배달부 친구!","JPN":"平和になった海辺がまた騒がしくなりそうだな！　さあ、後ろに乗ってくれ、配達員の友よ！","ENG":"I have a feeling that something is happening at the beach! Hop on, my delivery friend!","TWN":"看來好不容易恢復平靜的海灘，又要掀起一波風浪囉！上車吧，外送員朋友！"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아차차……. 이거, 과거의 자네가 너무 빨리 쓰러뜨렸나 보구만.","JPN":"やれやれ……過去の君があまりにも早く倒してしまったようだな。","ENG":"Oh... It seems the past-you defeated the Moderator too quickly.","TWN":"哎呀呀……過去的你太快就把敵人解決掉了啦！"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"방어령이 철회되기 전에 다들 토벌전이라고 몰려든 모양일세.","JPN":"防御令が撤回される前に、討伐戦だと思ってみんな集まってきたようだ。","ENG":"People came here for the raid before the red alert was withdrawn.","TWN":"防備令都還來不及撤銷，看來大家都是收到討伐戰通知才跑來的。"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"다들 그라운드 원에 있기 싫어서겠죠.","JPN":"みんなグラウンド・ワンに居たくないだけでしょう。","ENG":"That’s probably because they didn’t want to stay in Ground One.","TWN":"應該是因為大家都不想待在G1吧？"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"결국 조용한 휴식은 물건너가 버렸군요.","JPN":"結局静かな休暇は不可能な話でしたね。","ENG":"I suppose my relaxing vacation is over now.","TWN":"結果平靜的休假還是一場遊戲一場夢。"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그래서 이것도, 사장님의 계획에 포함되어 있던 상황인가요?","JPN":"それで、これも社長の計画に含まれていた状況ですか？","ENG":"So, were you expecting this as well?","TWN":"現在這個情況也在老闆的計畫中吧？"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하하. 가끔씩은 기분 좋은 우연이란 것도 있는 법이지.","JPN":"はは。たまには愉快な偶然というものもあるのさ。","ENG":"Well, I’ll just call it a pleasant coincidence.","TWN":"哈哈，偶爾也是會有這種美麗的誤會嘛～"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오늘은 이 소란스러움을 마음껏 즐겼으면 하는데, 자네 생각은 어떤가.","JPN":"今日はこの騒がしさを存分に楽んでもらいたいが、君の考えはどうかね？","ENG":"It seems today is the day we should enjoy ourselves, what do you think?","TWN":"今天就盡情享受這難得的熱鬧吧！副總意下如何？"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"찬성입니다. 사장님.","JPN":"賛成です、社長。","ENG":"I concur, Boss.","TWN":"我贊成，老闆。"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"그런데 방금 전, 문자가 한 통 들어왔군요.","JPN":"しかし先ほど、一通のメッセージが届きました。","ENG":"But then, I just got a message.","TWN":"只是我剛收到一封訊息。"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"기숙사 인테리어 비용 청구서가 왜 이 모양인지, 둘이서 차분하게 얘기해 볼까요?","JPN":"寮のインテリア費用請求書がなぜこうなってしまったか、2人でじっくり話してみましょうか。","ENG":"I think it’s time for us to have an in-depth discussion regarding the Dorm interior expenses.","TWN":"宿舍裝修請款單怎麼會這樣？我們兩個私下聊聊吧？"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"………….","JPN":"…………","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"아, 주인님. 그렇게 굳은 표정, 근엄해 보여서 멋지십니다.","JPN":"あ、ご主人様。その固まったような表情、とても謹厳にみえて素敵です。","ENG":"Master, your stiff face is so very stern. It’s great.","TWN":"喔！主人現在一臉鐵青，認真的男人最帥喔。"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"기념으로 남기실 수 있게 제가 인생샷 한 장 찍어 드리죠.","JPN":"私が記念写真を一枚撮ってあげますね。","ENG":"Let me take a picture of you to celebrate this day.","TWN":"我幫您拍張照留念吧！"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"                                                                                  TO BE CONTINUED?","JPN":"                                                                                  TO BE CONTINUED？","ENG":"TO BE CONTINUED?","TWN":" TO BE CONTINUED？"},"stage":{"bg":"SUMMER2_02","bgm":"THEMA_SUMMER_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};